import java.io.*;
import java.nio.file.*;
import java.util.*;

public class minigit {
    private static final String MINIGIT_DIR = ".minigit";
    private static final String INDEX_FILE = MINIGIT_DIR + "/index";
    private static final String OBJECTS_DIR = MINIGIT_DIR + "/objects";

    public static void main(String[] args) throws IOException {
        if (args.length == 0) {
            exit("No command specified");
        }

        String command = args[0];
        switch (command) {
            case "init":
                init();
                break;
            case "add":
                if (args.length < 2) {
                    exit("No file specified");
                }
                add(args[1]);
                break;
            case "commit":
                if (args.length < 2) {
                    exit("No message specified");
                }
                commit(args[1]);
                break;
            case "log":
                log();
                break;
            default:
                exit("Unknown command: " + command);
        }
    }

    private static void init() throws IOException {
        Path minigitPath = Paths.get(MINIGIT_DIR);
        if (Files.exists(minigitPath)) {
            exit("Repository already initialized");
        }

        Files.createDirectory(minigitPath);
        Files.createDirectory(Paths.get(OBJECTS_DIR));
        Files.createFile(Paths.get(INDEX_FILE));
        System.out.println("Initialized empty minigit repository");
    }

    private static void add(String filename) throws IOException {
        checkInitialized();

        Path filePath = Paths.get(filename);
        if (!Files.exists(filePath)) {
            exit("File not found: " + filename);
        }

        String content = Files.readString(filePath);
        String hash = sha1(content);

        Path objectPath = Paths.get(OBJECTS_DIR, hash);
        Files.writeString(objectPath, content);

        List<String> index = new ArrayList<>();
        Path indexPath = Paths.get(INDEX_FILE);
        if (Files.exists(indexPath)) {
            index.addAll(Files.readAllLines(indexPath));
        }

        boolean found = false;
        for (int i = 0; i < index.size(); i++) {
            String[] parts = index.get(i).split(" ", 2);
            if (parts.length == 2 && parts[1].equals(filename)) {
                index.set(i, hash + " " + filename);
                found = true;
                break;
            }
        }

        if (!found) {
            index.add(hash + " " + filename);
        }

        Files.write(indexPath, index);
    }

    private static void commit(String message) throws IOException {
        checkInitialized();

        List<String> index = Files.readAllLines(Paths.get(INDEX_FILE));
        if (index.isEmpty()) {
            exit("No files staged");
        }

        StringBuilder commitContent = new StringBuilder();
        for (String line : index) {
            commitContent.append(line).append("\n");
        }
        commitContent.append("\n").append(message);

        String hash = sha1(commitContent.toString());
        Path commitPath = Paths.get(OBJECTS_DIR, hash);
        Files.writeString(commitPath, commitContent.toString());

        Path headPath = Paths.get(MINIGIT_DIR, "HEAD");
        Files.writeString(headPath, hash);

        System.out.println("Committed with hash " + hash);
    }

    private static void log() throws IOException {
        checkInitialized();

        Path headPath = Paths.get(MINIGIT_DIR, "HEAD");
        if (!Files.exists(headPath)) {
            exit("No commits found");
        }

        String commitHash = Files.readString(headPath).trim();
        while (!commitHash.isEmpty()) {
            Path commitPath = Paths.get(OBJECTS_DIR, commitHash);
            if (!Files.exists(commitPath)) {
                break;
            }

            String content = Files.readString(commitPath);
            String[] lines = content.split("\n");
            StringBuilder message = new StringBuilder();
            boolean inMessage = false;
            for (String line : lines) {
                if (line.isEmpty()) {
                    inMessage = true;
                    continue;
                }
                if (inMessage) {
                    message.append(line).append("\n");
                }
            }

            System.out.println("commit " + commitHash);
            System.out.print(message.toString());
            System.out.println();

            commitHash = "";
        }
    }

    private static void checkInitialized() {
        if (!Files.exists(Paths.get(MINIGIT_DIR))) {
            exit("Repository not initialized");
        }
    }

    private static String sha1(String input) {
        try {
            java.security.MessageDigest md = java.security.MessageDigest.getInstance("SHA-1");
            byte[] digest = md.digest(input.getBytes());
            StringBuilder sb = new StringBuilder();
            for (byte b : digest) {
                sb.append(String.format("%02x", b));
            }
            return sb.toString();
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    private static void exit(String message) {
        System.err.println(message);
        System.exit(1);
    }
}
